var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완…….","JPN":"スワン……","ENG":"Swan...","TWN":"史旺……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"스완 클레어, 맞지?","JPN":"スワン・クレアだよな？","ENG":"You're Swan Claire, correct?","TWN":"你是史旺·克萊爾，對吧？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"네 정체를 알고 있다.","JPN":"俺はお前の正体を知っている。","ENG":"I know who you are.","TWN":"我知道你的真實身份。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"죽고 싶지 않으면, 순순히 내 말을 따르도록.","JPN":"死にたくないなら、大人しく言うことを聞け。","ENG":"It's best for you to listen to my words if you want to live.","TWN":"如果不想死的話，就乖乖聽我的話。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"교활한 여배우라고 들었는데, 그래봤자 아직 여물지 못한 여자애로군.","JPN":"狡猾な女優だと聞いたが、所詮はまだ未熟な女の子だったか。","ENG":"I heard you were a cunning actress, but it turns out that you're just a little girl.","TWN":"聽說你是個狡猾的女演員，不過在我看來，你就是個不成熟的小女孩。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"넌 실수한 거다, 스완.","JPN":"残念だったな、スワン。","ENG":"You made a mistake, Swan.","TWN":"你犯了個大錯，史旺。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"세간에는 지금 심야의 살인마라는 녀석이 도시를 배회하며 먹잇감을 노린다고 하지.","JPN":"世間では今、深夜の殺人鬼とやらが獲物を探し徘徊していると噂になっているらしいが……","ENG":"The Midnight Killer is out loose in the city looking for prey.","TWN":"傳聞說現在有個午夜殺人魔在城市裡尋找獵物。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 이런 상황에서 시체 한 구쯤 더 생긴다고 달라질 건 아무것도 없어.","JPN":"こんな状況で死体がもう一体見つかったところで、何も変わりはしない。","ENG":"So another body on the streets doesn't change anything.","TWN":"在這種情況下，多一具屍體不會有什麼不同。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"다들 널 미치광이 살인마에게 살해당한 불쌍한 소녀라고 생각할 테니까.","JPN":"皆お前のことを殺人鬼に殺された哀れな少女だとしか思わないだろうから。","ENG":"Everyone will think that another poor girl fell victim to a crazy killer.","TWN":"大家都只會認為你是又一個被瘋子殺害的可憐少女。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"왜 아무 말이 없지? 겁이라도 먹었나?","JPN":"なんで黙り込んでいる？　怖気づいたか？","ENG":"Why aren't you saying anything? Cat got your tongue?","TWN":"怎麼一句話也不說？是害怕了嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"자, 죽고 싶지 않으면, 바른대로 말해.","JPN":"さ、死にたくなければ素直に言え。","ENG":"Now, tell me the truth unless you want to die.","TWN":"好了，如果不想死的話，就老實說吧。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>사진</color>은 어디에 있나?","JPN":"<color=#ffd34c>写真</color>はどこにある？","ENG":"Where is the <color=#ffd34c>photo</color>?","TWN":"<color=#ffd34c>照片</color>在哪裡？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"죽고 싶지 않으면?","JPN":"死にたくなければ？","ENG":"Unless I want to die?","TWN":"不想死的話？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요. 제가 죽으면 가장 곤란해질 사람은 제가 아니라 당신일 텐데요?","JPN":"さあ、私が死んで一番困るのはあなたのはずですが？","ENG":"Well. Wouldn't it be you who'll be in trouble if I die?","TWN":"未必，我要是死了，最麻煩的可不是我，而是你吧？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고……?","JPN":"なんだと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아랫사람을 대하는 데 익숙한 듯, 딱딱하고 고압적인 말투…….","JPN":"目下の人間を扱うことに慣れているような、硬く高圧的な喋り方……","ENG":"That stiff and overbearing tone you use to order around your subordinates...","TWN":"習慣了對待下屬，生硬而高壓的語氣……"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"꽤나 높은 직위를 가지셨던 것 같군요. 당신을 따르던 사람이 제법 많았을지도 모르죠.","JPN":"かなりお高い職位をお持ちになっていたようですね。大勢の人に仕えられていたかもしれません。","ENG":"Seems like you were in a fairly high position. I'm sure there used to be many under you.","TWN":"看來你曾經擁有相當高的職位，追隨你的人可能還不少呢。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 오른손을 미세하게 떨고 있어요. 아무래도 서부전선에서 신경을 다쳤겠죠.","JPN":"ですが、よく見ると右手が震えている。おそらく、西部戦線で神経をやられたのでしょう。","ENG":"But your right hand is trembling slightly. I assume you injured the nerves in your hand in the western front?","TWN":"但是你的右手在微微顫，應該是在西部前線受了傷，傷到神經了吧。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇게 손을 떨면 총을 잡을 수 없을 테니, 어쩔 수 없이 퇴역하셨겠고요.","JPN":"そんなに手が震えては銃を握ることも大変でしょう。やむを得ず退役したに違いありません。","ENG":"You can't possibly wield a gun when your hands are shaking like that. Which means you have been discharged.","TWN":"一個無法再握住槍，只能無奈退役的高階軍官……"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"그, 그걸 어떻게……?","JPN":"な、なぜそれを……？","ENG":"H-how did you know that...?","TWN":"你，你怎麼會……？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 애석한 일이네요.","JPN":"まったく残念ですね。","ENG":"It truly is a pity.","TWN":"真是令人惋惜。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"나라를 위해 목숨을 바친 애국자가 퇴역 후, 높으신 분들 심부름꾼 노릇이나 하게 되다니.","JPN":"国のために命を捧げて戦ったのに、退役後はお偉いさんの使いっぱしりになり下がるなんて。","ENG":"A patriot risks his life for his country, then ends up as an errand boy for some high-ranking official.","TWN":"為國家獻出生命的愛國者退居幕後，竟然成為替高層跑腿的。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STRANGER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"STRANGER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 당신 <color=#ffd34c>의뢰인</color>에 대해 너무나 잘 알고 있답니다.","JPN":"私はあなたの<color=#ffd34c>依頼人</color>についてよく知っていますよ。","ENG":"I know your <color=#ffd34c>client</color> better than you think.","TWN":"我可是非常了解你的<color=#ffd34c>委託人</color>。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 그분께서 최대한 조용한 일 처리를 원하신다는 것 또한 말이죠.","JPN":"そしてその方が、なるべく静かにことを進めたいと望んでいらっしゃるということも。","ENG":"Also, he wants things to be done as quietly as possible.","TWN":"而且那位希望儘量低調行事。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"단도직입적으로 말씀드리죠.","JPN":"単刀直入に言いましょう。","ENG":"I will be honest with you.","TWN":"我就直接了當地說吧。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그분께서 원하는 사진은 지금 제 손에 없답니다.","JPN":"その方がお探しの写真は、今私の手元にはありません。","ENG":"I don't have the photo he demands with me right now.","TWN":"他想要的照片現在不在我手上。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};